package com.google.gson.internal;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Method;

import com.google.gson.ReflectionAccessFilter;
import com.google.gson.ReflectionAccessFilter.FilterResult;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.MockedStatic;
import org.mockito.junit.jupiter.MockitoExtension;

@ExtendWith(MockitoExtension.class)
class ReflectionAccessFilterHelperTest {

  @Test
  void canAccess_returnsTrue_whenAccessCheckerReturnsTrue() throws Exception {
    AccessibleObject accessibleObject = mock(AccessibleObject.class);
    Object obj = new Object();

    try (MockedStatic<AccessChecker> accessCheckerMockedStatic = mockStatic(AccessChecker.class)) {
      AccessChecker mockInstance = mock(AccessChecker.class);
      accessCheckerMockedStatic.when(() -> AccessChecker.INSTANCE).thenReturn(mockInstance);
      when(mockInstance.canAccess(accessibleObject, obj)).thenReturn(true);

      boolean result = ReflectionAccessFilterHelper.canAccess(accessibleObject, obj);

      assertTrue(result);
      verify(mockInstance).canAccess(accessibleObject, obj);
    }
  }

  @Test
  void canAccess_returnsFalse_whenAccessCheckerReturnsFalse() throws Exception {
    AccessibleObject accessibleObject = mock(AccessibleObject.class);
    Object obj = new Object();

    try (MockedStatic<AccessChecker> accessCheckerMockedStatic = mockStatic(AccessChecker.class)) {
      AccessChecker mockInstance = mock(AccessChecker.class);
      accessCheckerMockedStatic.when(() -> AccessChecker.INSTANCE).thenReturn(mockInstance);
      when(mockInstance.canAccess(accessibleObject, obj)).thenReturn(false);

      boolean result = ReflectionAccessFilterHelper.canAccess(accessibleObject, obj);

      assertFalse(result);
      verify(mockInstance).canAccess(accessibleObject, obj);
    }
  }

  @Test
  void privateConstructor_isPrivate() throws Exception {
    var constructor = ReflectionAccessFilterHelper.class.getDeclaredConstructor();
    assertTrue((constructor.getModifiers() & java.lang.reflect.Modifier.PRIVATE) != 0);
    constructor.setAccessible(true);
    constructor.newInstance();
  }
}
